from collections import defaultdict

class Solution:
    def maxOutput(self, n, edges, price):
        graph = defaultdict(list)
        for a, b in edges:
            graph[a].append(b)
            graph[b].append(a)
        best = 0
        for root in range(n):
            visited = {root}
            stack = [(root, price[root])]
            max_sum = price[root]
            while stack:
                node, s = stack.pop()
                if s > max_sum:
                    max_sum = s
                for nxt in graph[node]:
                    if nxt not in visited:
                        visited.add(nxt)
                        stack.append((nxt, s + price[nxt]))
            min_sum = price[root]
            cost = max_sum - min_sum
            if cost > best:
                best = cost
        return best

