var maxOutput = function(n, edges, price) {
    const graph = new Map();
    for (let i = 0; i < n; i++) graph.set(i, []);
    for (const [a, b] of edges) {
        graph.get(a).push(b);
        graph.get(b).push(a);
    }
    let ans = 0;
    function dfs(node, parent) {
        let max1 = price[node];
        let max2 = 0;
        for (const child of graph.get(node)) {
            if (child === parent) continue;
            const [c1, c2] = dfs(child, node);
            ans = Math.max(ans, max1 + c2, max2 + c1);
            max1 = Math.max(max1, c1 + price[node]);
            max2 = Math.max(max2, c2 + price[node]);
        }
        return [max1, max2];
    }
    dfs(0, -1);
    return ans;
};
